// WebGPU compat test #5 — THE points question, settled. Renders one point via
// the aeon-3d instance layout: a per-vertex corner quad (slot 0, float32x2,
// stride 8) + a per-INSTANCE buffer (slot 1, stride 36) with ipos at offset 0
// and icolor at offset 24 — the EXACT stride-36/vec3@24 layout that's the prime
// suspect for the WebKit misplacement. Float vertex data is byte-packed in pure
// JS (no DataView; identical in Deno + monster). If the instanced read is
// correct on wgpu, the point lands at ipos's projection AND is GREEN (icolor@24
// read correctly). Deno (oracle) and monster must agree.

function f32bytes(x) {
  if (x === 0) return [0, 0, 0, 0];
  const sign = x < 0 ? 1 : 0;
  x = Math.abs(x);
  let e = Math.floor(Math.log2(x));
  let m = x / Math.pow(2, e);
  if (m < 1) { m *= 2; e -= 1; }
  if (m >= 2) { m /= 2; e += 1; }
  const exp = e + 127;
  const mant = Math.round((m - 1) * Math.pow(2, 23));
  const bits = ((sign << 31) | (exp << 23) | mant) >>> 0;
  return [bits & 0xff, (bits >>> 8) & 0xff, (bits >>> 16) & 0xff, (bits >>> 24) & 0xff];
}
// NB: monster passes arrays BY VALUE into functions, so a mutate-through-helper
// (arr.push inside a fn) is lost. Assemble with concat (returns a new array).
const out = {};
const adapter = await navigator.gpu.requestAdapter();
const device = await adapter.requestDevice();
const W = 64, H = 64;
const tex = device.createTexture({
  size: { width: W, height: H }, format: 'rgba8unorm',
  usage: GPUTextureUsage.RENDER_ATTACHMENT | GPUTextureUsage.COPY_SRC,
});

let corner = [];
const cc = [[0, 0], [1, 0], [0, 1], [1, 1]];
for (let k = 0; k < cc.length; k++) {
  corner = corner.concat(f32bytes(cc[k][0])).concat(f32bytes(cc[k][1]));
}
const cornerBuf = device.createBuffer({ size: corner.length, usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(cornerBuf, 0, new Uint8Array(corner));

let inst = [];
inst = inst.concat(f32bytes(0.3)).concat(f32bytes(-0.4)).concat(f32bytes(0.0)); // ipos   @0  → NDC (0.3,-0.4)
inst = inst.concat(f32bytes(0.0)).concat(f32bytes(0.0)).concat(f32bytes(0.0));  // normal @12 (padding, unread)
inst = inst.concat(f32bytes(0.0)).concat(f32bytes(1.0)).concat(f32bytes(0.0));  // icolor @24 = GREEN
const instBuf = device.createBuffer({ size: inst.length, usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST });
device.queue.writeBuffer(instBuf, 0, new Uint8Array(inst));

const shader = device.createShaderModule({
  code: `
    struct VSOut { @builtin(position) pos: vec4f, @location(0) vColor: vec3f };
    @vertex fn vs(@location(0) corner: vec2f, @location(1) ipos: vec3f, @location(2) icolor: vec3f) -> VSOut {
      var o: VSOut;
      o.vColor = icolor;
      var clip = vec4f(ipos, 1.0);
      let sizePx = 16.0;
      let viewport = vec2f(64.0, 64.0);
      clip = vec4f(clip.xy + (corner - vec2f(0.5)) * sizePx * (2.0 / viewport) * clip.w, clip.zw);
      o.pos = clip;
      return o;
    }
    @fragment fn fs(in: VSOut) -> @location(0) vec4f { return vec4f(in.vColor, 1.0); }
  `,
});
const pipeline = device.createRenderPipeline({
  layout: 'auto',
  vertex: {
    module: shader, entryPoint: 'vs',
    buffers: [
      { arrayStride: 8, attributes: [{ shaderLocation: 0, offset: 0, format: 'float32x2' }] },
      { arrayStride: 36, stepMode: 'instance', attributes: [
        { shaderLocation: 1, offset: 0, format: 'float32x3' },
        { shaderLocation: 2, offset: 24, format: 'float32x3' },
      ] },
    ],
  },
  fragment: { module: shader, entryPoint: 'fs', targets: [{ format: 'rgba8unorm' }] },
  primitive: { topology: 'triangle-strip' },
});
const enc = device.createCommandEncoder();
const pass = enc.beginRenderPass({
  colorAttachments: [{ view: tex.createView(), loadOp: 'clear', storeOp: 'store', clearValue: { r: 0, g: 0, b: 0, a: 1 } }],
});
pass.setPipeline(pipeline);
pass.setVertexBuffer(0, cornerBuf);
pass.setVertexBuffer(1, instBuf);
pass.draw(4, 1);
pass.end();
const bpr = W * 4;
const rb = device.createBuffer({ size: bpr * H, usage: GPUBufferUsage.COPY_DST | GPUBufferUsage.MAP_READ });
enc.copyTextureToBuffer({ texture: tex }, { buffer: rb, bytesPerRow: bpr }, { width: W, height: H });
device.queue.submit([enc.finish()]);
await rb.mapAsync(GPUMapMode.READ);
const px = new Uint8Array(rb.getMappedRange());
let sx = 0, sy = 0, green = 0, red = 0;
for (let y = 0; y < H; y++) for (let x = 0; x < W; x++) {
  const o = y * bpr + x * 4;
  if (px[o + 1] > 200 && px[o] < 60 && px[o + 2] < 60) { green++; sx += x; sy += y; }
  if (px[o] > 200 && px[o + 1] < 60) red++;
}
rb.unmap();
out.green = green;
out.red = red;
out.cx = green ? Math.round(sx / green) : -1;
out.cy = green ? Math.round(sy / green) : -1;
out.placedRight = Math.abs(out.cx - 42) <= 1 && Math.abs(out.cy - 45) <= 1;
out.colorRight = green > 100 && red === 0;
console.log('__RESULT__ ' + JSON.stringify(out));
